var dc = tree.current_scene.deployment_controller
var models = GameState.get_unit(dc.unit_id).models
var candidates = [Vector2(1400,2350), Vector2(1300,2350), Vector2(900,2350), Vector2(1650,1300), Vector2(1650,700), Vector2(100,1300), Vector2(100,900), Vector2(1400,2300), Vector2(700,2350), Vector2(1650,1400), Vector2(500,2350), Vector2(1200,2350)]
var placed = 0
for c in candidates:
	if placed >= 2:
		break
	if dc._validate_reinforcement_position(c, models[dc.model_idx], 0.0):
		dc.try_place_at(c)
		placed = dc.get_placed_count()
return dc.get_placed_count()

